mapper.select:
SELECT
    a.id AS "id",
    a.acount AS "acount",
    a.eqno AS "eqno",
    a.idno AS "idno",
    a.nickname AS "nickname",
    a.mbid AS "mbid",
    a.mbname AS "mbname",
    a.mbda AS "mbda",
    a.lianghao AS "lianghao",
    a.state AS "state",
    a.two_factor_code AS "twoFactorCode",
    a.two_factor_time AS "twoFactorTime",
    a.create_date AS "createDate"
FROM t_member a

    a.two_factor_code IS NOT NULL
    ${dataScope}

        AND a.acount = #{acount}


        AND a.idno = #{idno}


        AND a.nickname LIKE concat('%',#{nickname},'%')


        AND (a.nickname = #{key} or a.phone = #{key} or a.acount = #{key} or a.idno = #{key} or a.lianghao = #{key})


        AND a.state = #{state}


        AND a.invitid = #{invitid}


        AND a.isneibu = #{isneibu}


        AND a.noadd = #{noadd}


        AND a.isvip = #{isvip}


        AND a.lianghao = #{lianghao}


        AND a.create_date BETWEEN #{beginCreateDate} AND #{endCreateDate}




        ORDER BY ${page.orderBy}


        ORDER BY a.create_date DESC

SELECT
    a.id AS "id",
    a.acount AS "acount",
    a.eqno AS "eqno",
    a.idno AS "idno",
    a.nickname AS "nickname",
    a.paypwd AS "paypwd",
    a.password AS "password",
    a.mbid AS "mbid",
    a.mbname AS "mbname",
    a.mbda AS "mbda",
    a.lianghao AS "lianghao",
    a.state AS "state",
    a.create_date AS "createDate"
FROM t_member a

    a.mbname IS NOT NULL
    ${dataScope}

        AND a.acount = #{acount}


        AND (a.idno = #{idno} OR a.lianghao = #{idno})


        AND a.nickname LIKE concat('%',#{nickname},'%')


        AND (a.nickname = #{key} or a.phone = #{key} or a.acount = #{key} or a.idno = #{key} or a.lianghao = #{key})


        AND a.state = #{state}


        AND a.invitid = #{invitid}


        AND a.isneibu = #{isneibu}


        AND a.noadd = #{noadd}


        AND a.isvip = #{isvip}


        AND a.lianghao LIKE concat('%', #{lianghao}, '%')


        AND a.create_date BETWEEN #{beginCreateDate} AND #{endCreateDate}


        AND a.mbname = #{mbname}




        ORDER BY ${page.orderBy}


        ORDER BY a.create_date DESC
